class Solution {
    private ListNode head;

    // @return: nothing
    public void deleteDuplicates () {
        while (head!= null && head.val!= head.next.val) {
            head = head.next;
        }

        while (head!= null) {
            ListNode next = head.next;

            while (next!= null && next.val == head.val) {
                next = next.next;
            }

            head.next = next;
            head = next;
        }
    }
};
